171	// --- createComment ---
172	export function createComment(cardId, data) {
173	  const { author, content } = data;
174	  const id = uuidv4();
175	  const created_at = Date.now();
176	  try {
177	    stmts.insertComment.run({ id, card_id: cardId, author, content, created_at });
178	  } catch (err) {
179	    if (err.code === 'SQLITE_CONSTRAINT_FOREIGNKEY') {
180	      throw new ForeignKeyError(`Card not found: ${cardId}`);
181	    }
182	    throw new DatabaseError(err.message);
183	  }
184	  return stmts.getCommentById.get(id);
185	}
