app.get('/health/ready', (_req, res) => {
  const database = getDb();
  let dbOk = false;
  try { database?.prepare('SELECT 1').get(); dbOk = true; } catch { /* */ }
  const wsOk = getWsState();
  const ready = dbOk;
  return res.status(ready ? 200 : 503).json({
    status: ready ? 'ready' : 'unavailable',
    db: dbOk, ws: wsOk,
  });
});
```

**Metrics endpoint:**
